from collections import deque

class Solution:
    def countStudents(self, students, sandwiches):
        q = deque(students)
        stack = list(sandwiches)
        i = 0
        stalled = 0
        while q and i < len(stack):
            if q[0] == stack[i]:
                q.popleft()
                i += 1
                stalled = 0
            else:
                q.append(q.popleft())
                stalled += 1
                if stalled == len(q):
                    break
        return len(q)

