class Solution:
    def countStudents(self, students, sandwiches):
        ones = sum(students)
        zeros = len(students) - ones
        for s in sandwiches:
            if s == 0:
                if zeros == 0:
                    break
                zeros -= 1
            else:
                if ones == 0:
                    break
                ones -= 1
        return zeros + ones

