var countStudents = function(students, sandwiches) {
  let ones = students.reduce((a, b) => a + b, 0);
  let zeros = students.length - ones;
  for (const s of sandwiches) {
    if (s === 0) {
      if (zeros === 0) break;
      zeros--;
    } else {
      if (ones === 0) break;
      ones--;
    }
  }
  return zeros + ones;
};
